// Writes exclusively to reminder_log.json -- an isolated, append-only
// file handler, serialized the same way as the Global DNC engine.
// NEVER writes state flags into contacts.json/pipeline.json directly,
// which is exactly what caused the write-lock collision this fixes (B1).

const fs = require('fs');
const path = require('path');

let intakeLog = [];
try { intakeLog = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8')); } catch (e) {}

let reminderLog = {};
const reminderPath = path.join('Shared', 'reminder_log.json');
try { reminderLog = JSON.parse(fs.readFileSync(reminderPath, 'utf8')); } catch (e) {}

const now = Date.now();
const DROP_THRESHOLD_MS = 48 * 60 * 60 * 1000;
const due = [];

for (const entry of intakeLog) {
  const key = entry.project_prefix + ':' + entry.contact_hash;
  const sent = reminderLog[key] || {};

  if (entry.status === 'nda_pending' && !sent.nda_drop && (now - new Date(entry.created_at).getTime()) > DROP_THRESHOLD_MS) {
    due.push({ ...entry, reminder_type: 'nda_drop', key });
  }
  if (entry.status === 'intake_complete' && !sent.payment_drop && (now - new Date(entry.intake_complete_at).getTime()) > DROP_THRESHOLD_MS) {
    due.push({ ...entry, reminder_type: 'payment_drop', key });
  }
}

return due.map(d => ({ json: d }));

// Serialized write, same pattern as Global DNC -- one workflow, one
// append operation at a time, never touching the contended primary files.
const fs = require('fs');
const path = require('path');
const reminderPath = path.join('Shared', 'reminder_log.json');

let reminderLog = {};
try { reminderLog = JSON.parse(fs.readFileSync(reminderPath, 'utf8')); } catch (e) {}

if (!reminderLog[$json.key]) reminderLog[$json.key] = {};
reminderLog[$json.key][$json.reminder_type === 'nda_drop' ? 'nda_drop' : 'payment_drop'] = new Date().toISOString();

fs.writeFileSync(reminderPath, JSON.stringify(reminderLog, null, 2), 'utf8');
return [{ json: $json }];
